mapper.update:
UPDATE RESERVATION
SET status       = #{status},
    completed_at = SYSDATE,
    fail_reason  = #{failReason, jdbcType=VARCHAR}
WHERE reservation_id = #{reservationId}

mapper.select:
SELECT *
FROM (
    SELECT reservation_id, from_account, to_account, amount,
           memo, scheduled_at, status, created_at, completed_at, fail_reason
    FROM RESERVATION
    WHERE from_account = #{accountNo}
       OR to_account   = #{accountNo}
    ORDER BY scheduled_at DESC
)
WHERE ROWNUM <= #{limit}
